import { LlamaIndex } from 'llamaindex';

const index = await LlamaIndex.VectorStoreIndex.fromDocuments([
  // Your documents
]);

const queryEngine = index.asQueryEngine({
  similarityTopK: 3,
  streaming: true
});

export async function handleVoiceQuery(
  transcript: string,
  conversationHistory: string[]
): Promise<string> {
  const response = await queryEngine.query({
    query: transcript,
    chatHistory: conversationHistory,
  });

  return response.response;
}

import time
import requests

def synthesize_speech(text: str, voice_id: str) -> bytes:
    start_time = time.time()

    response = requests.post(
        "https://api.elevenlabs.io/v1/text-to-speech/" + voice_id,
        headers={"xi-api-key": "YOUR_KEY"},
        json={
            "text": text,
            "model_id": "eleven_monolingual_v1",
            "voice_settings": {
                "stability": 0.5,
                "similarity_boost": 0.8
            }
        }
    )

    latency = time.time() - start_time
    if latency > 0.1:  # 100ms budget
        print(f"TTS latency warning: {latency*1000:.0f}ms")

    return response.content

