from vex import verify
from llama_index.core import VectorStoreIndex

index = VectorStoreIndex.from_documents(documents)
query_engine = index.as_query_engine()

def safe_voice_query(query: str) -> str:
    @verify(
        guards=[
            "response.appropriateness > 0.9",
            "latency.total < 300ms",
            "safety.nsfw == false",
            "response.coherent_with_context"
        ],
        fallback="I need more context to answer accurately."
    )
    def protected_query():
        return str(query_engine.query(query))

    return protected_query()

